12	export interface BlockRow {
13	  id: string;
14	  workspace_id: string;
15	  session_id: string;
16	  content_hash: string;
17	  kind: BlockKind;
18	  volatility: Volatility;
19	  is_pinned: number; // SQLite stores booleans as 0/1; use rowToBlock() to convert
20	  token_count: number;
21	  added_at_turn: number;
22	  last_referenced_at_turn: number;
23	  unused_turns: number;
24	  is_stub: number;
25	  stub_summary: string | null;
26	  refetch_handle: string | null;
27	  created_at: number;
28	  updated_at: number;
29	}
30	
31	export function rowToBlock(row: BlockRow): Block {
32	  return {
33	    ...row,
34	    is_pinned: row.is_pinned === 1,
35	    is_stub: row.is_stub === 1,
36	  };
37	}
