198	       input_tokens, output_tokens,
199	       cache_creation_5m_tokens, cache_creation_1h_tokens, cache_read_tokens,
200	       effective_cost_units, prefix_breakpoint_hash, middle_breakpoint_hash,
201	       pruned_blocks_count, keepalive_pings_since_last_turn, created_at)
202	    VALUES
203	      (@id, @workspace_id, @session_id, @turn_number, @model,
204	       @input_tokens, @output_tokens,
