239	    stubSummary: string | null,
240	    updatedAt: number
241	  ) => void markStubStmt.run(refetchHandle, stubSummary, updatedAt, id);
242	
243	  db.insertTurn = (p: InsertTurnParams) => void insertTurnStmt.run(p);
244	
245	  db.getTurn = (id: string) =>
246	    (getTurnStmt.get(id) as TurnRow | undefined) ?? null;
247	
248	  db.insertBlockReference = (p: InsertBlockReferenceParams): number => {
249	    const info = insertBlockReferenceStmt.run(p);
250	    return Number(info.lastInsertRowid);
251	  };
252	
253	  db.getBlockReferencesForTurn = (turnId: string) =>
254	    getBlockReferencesForTurnStmt.all(turnId) as BlockReferenceRow[];
