9	function canonicalize(value: unknown): string {
10	  if (value === undefined || value === null) return "null";
11	  if (typeof value !== "object") return JSON.stringify(value);
12	  if (Array.isArray(value)) {
13	    return "[" + value.map(canonicalize).join(",") + "]";
14	  }
15	  const obj = value as Record<string, unknown>;
16	  const keys = Object.keys(obj)
17	    .filter((k) => obj[k] !== undefined)
18	    .sort();
19	  return (
20	    "{" +
21	    keys
22	      .map((k) => JSON.stringify(k) + ":" + canonicalize(obj[k]))
23	      .join(",") +
24	    "}"
25	  );
26	}
