1	import type { Volatility } from "../types/index.js";
2	import type {
3	  Classification,
4	  ClassifierConfig,
5	  Signal,
6	  UnclassifiedBlock,
7	} from "./types.js";
8	import { DEFAULT_FALLBACK, runRules } from "./rules.js";
9	import { KIND_TO_VOLATILITY, PIN_VOLATILITY } from "./volatility-map.js";
10	import { globMatch } from "./glob.js";
11	
12	export type {
13	  Classification,
14	  ClassifierConfig,
15	  Signal,
16	  UnclassifiedBlock,
17	} from "./types.js";
18	
19	function makeErrorFallback(): Classification {
20	  return {
21	    kind: "user_message",
22	    volatility: "VOLATILE",
23	    isPinned: false,
24	    signals: ["error:fallback"],
25	  };
26	}
27	
28	export function classifyBlock(
29	  input: UnclassifiedBlock,
30	  config: ClassifierConfig,
31	): Classification | null {
32	  try {
33	    const fp = input.filePath;
34	
35	    if (fp && config.exclude.some((p) => globMatch(p, fp))) {
36	      return null;
37	    }
38	
39	    const ruled = runRules(input, config) ?? DEFAULT_FALLBACK;
40	
41	    // Stubs inherit the volatility of the block they replaced so cache-
42	    // breakpoint positions stay stable across the M5 prune-and-restore
43	    // cycle. The KIND_TO_VOLATILITY map intentionally does NOT include
44	    // a stub entry — the type narrows it away.
45	    let volatility: Volatility =
46	      ruled.kind === "stub"
47	        ? (input.incomingVolatility ?? "STABLE")
48	        : KIND_TO_VOLATILITY[ruled.kind];
49	
50	    const signals: Signal[] = [...ruled.signals];
51	    let isPinned = false;
52	
53	    if (fp && config.pin.some((p) => globMatch(p, fp))) {
54	      isPinned = true;
55	      volatility = PIN_VOLATILITY;
56	      signals.push("pin:match");
57	    }
58	
59	    return {
60	      kind: ruled.kind,
61	      volatility,
62	      isPinned,
63	      signals,
64	    };
65	  } catch (err) {
66	    // classifyBlock must never throw; log and fail-open. M7 will swap
67	    // console for the project's structured logger so ops can alert on
68	    // `error:fallback` signal rate.
69	    console.error("[cachelane] classifyBlock error", err);
70	    return makeErrorFallback();
71	  }
72	}
73	
74	export function classifyBlocks(
75	  inputs: UnclassifiedBlock[],
76	  config: ClassifierConfig,
77	): Classification[] {
78	  return inputs
79	    .map((input) => classifyBlock(input, config))
80	    .filter((c): c is Classification => c !== null);
81	}
