1	import type {
2	  AnthropicCacheControl,
3	  AnthropicMessagesRequest,
4	  Breakpoints,
5	  RegionBoundaries,
6	} from "./types.js";
7	
8	const PREFIX_MARKER: AnthropicCacheControl = { type: "ephemeral", ttl: "5m" };
9	const MIDDLE_MARKER: AnthropicCacheControl = { type: "ephemeral", ttl: "5m" };
10	
11	export function mutateRequest(
12	  originalRequest: AnthropicMessagesRequest,
13	  boundaries: RegionBoundaries,
14	  breakpoints: Breakpoints,
15	): AnthropicMessagesRequest {
16	  const out: AnthropicMessagesRequest = {
17	    ...originalRequest,
18	    system: originalRequest.system?.map((s) => ({ ...s })),
19	    tools: originalRequest.tools?.map((t) => ({ ...t })),
20	    messages: originalRequest.messages.map((m) => ({
21	      ...m,
22	      content: m.content.map((c) => ({ ...c })) as typeof m.content,
23	    })),
24	  };
25	
26	  // Prefix breakpoint: marker on the last tool, or the last system block if no tools.
27	  if (out.tools && out.tools.length > 0) {
28	    out.tools[out.tools.length - 1].cache_control = PREFIX_MARKER;
29	  } else if (out.system && out.system.length > 0) {
30	    out.system[out.system.length - 1].cache_control = PREFIX_MARKER;
31	  }
32	
33	  // Middle breakpoint: marker on the last content item of the last SEMI message.
34	  if (
35	    breakpoints.include_middle_breakpoint &&
36	    boundaries.middle_end_in_messages !== null &&
37	    boundaries.middle_end_in_messages > 0
38	  ) {
39	    const lastSemiIdx = boundaries.middle_end_in_messages - 1;
40	    const msg = out.messages[lastSemiIdx];
41	    if (msg && msg.content.length > 0) {
42	      const lastContent = msg.content[msg.content.length - 1];
43	      lastContent.cache_control = MIDDLE_MARKER;
44	    }
45	  }
46	
47	  return out;
48	}
