149	export function openDatabase(dbPath: string): CachelaneDb {
150	  fs.mkdirSync(path.dirname(dbPath), { recursive: true });
151	
152	  let rawDb: Database.Database;
153	  try {
154	    rawDb = tryOpen(dbPath);
155	    const result = rawDb.pragma("integrity_check") as {
156	      integrity_check: string;
157	    }[];
158	    if (result[0].integrity_check !== "ok") {
159	      rawDb.close();
160	      throw new Error("integrity_check failed");
161	    }
162	  } catch {
163	    const corruptPath = `${dbPath}.corrupt-${Date.now()}`;
164	    try {
165	      fs.renameSync(dbPath, corruptPath);
166	    } catch {
167	      // ignore if rename fails (e.g. file already gone)
168	    }
169	    rawDb = tryOpen(dbPath);
170	  }
171	
172	  const insertBlockStmt = rawDb.prepare(`
173	    INSERT INTO blocks
174	      (id, workspace_id, session_id, content_hash, kind, volatility,
175	       is_pinned, token_count, added_at_turn, last_referenced_at_turn,
176	       unused_turns, is_stub, stub_summary, refetch_handle,
177	       created_at, updated_at)
178	    VALUES
179	      (@id, @workspace_id, @session_id, @content_hash, @kind, @volatility,
180	       @is_pinned, @token_count, @added_at_turn, @last_referenced_at_turn,
181	       @unused_turns, @is_stub, @stub_summary, @refetch_handle,
182	       @created_at, @updated_at)
183	  `);
184	
185	  const getBlockStmt = rawDb.prepare("SELECT * FROM blocks WHERE id = ?");
186	
187	  const incrementUnusedTurnsStmt = rawDb.prepare(
188	    "UPDATE blocks SET unused_turns = unused_turns + 1, updated_at = ? WHERE id = ?"
189	  );
190	
191	  const markStubStmt = rawDb.prepare(
192	    "UPDATE blocks SET is_stub = 1, refetch_handle = ?, stub_summary = ?, updated_at = ? WHERE id = ?"
193	  );
194	
195	  const insertTurnStmt = rawDb.prepare(`
196	    INSERT INTO turns
197	      (id, workspace_id, session_id, turn_number, model,
198	       input_tokens, output_tokens,
199	       cache_creation_5m_tokens, cache_creation_1h_tokens, cache_read_tokens,
200	       effective_cost_units, prefix_breakpoint_hash, middle_breakpoint_hash,
201	       pruned_blocks_count, keepalive_pings_since_last_turn, created_at)
202	    VALUES
203	      (@id, @workspace_id, @session_id, @turn_number, @model,
204	       @input_tokens, @output_tokens,
205	       @cache_creation_5m_tokens, @cache_creation_1h_tokens, @cache_read_tokens,
206	       @effective_cost_units, @prefix_breakpoint_hash, @middle_breakpoint_hash,
207	       @pruned_blocks_count, @keepalive_pings_since_last_turn, @created_at)
208	  `);
209	
210	  const getTurnStmt = rawDb.prepare("SELECT * FROM turns WHERE id = ?");
211	
212	  const insertBlockReferenceStmt = rawDb.prepare(`
213	    INSERT INTO block_references (block_id, turn_id, reference_type, evidence, created_at)
214	    VALUES (@block_id, @turn_id, @reference_type, @evidence, @created_at)
215	  `);
216	
217	  const getBlockReferencesForTurnStmt = rawDb.prepare(
218	    "SELECT * FROM block_references WHERE turn_id = ? ORDER BY id"
219	  );
220	
221	  const db = rawDb as CachelaneDb;
222	
223	  db.insertBlock = (p: InsertBlockParams) =>
224	    void insertBlockStmt.run({
225	      ...p,
226	      is_pinned: p.is_pinned ? 1 : 0,
227	      is_stub: p.is_stub ? 1 : 0,
228	    });
229	
230	  db.getBlock = (id: string) =>
231	    (getBlockStmt.get(id) as BlockRow | undefined) ?? null;
232	
233	  db.incrementUnusedTurns = (id: string, updatedAt: number) =>
234	    void incrementUnusedTurnsStmt.run(updatedAt, id);
235	
236	  db.markStub = (
237	    id: string,
238	    refetchHandle: string,
239	    stubSummary: string | null,
240	    updatedAt: number
241	  ) => void markStubStmt.run(refetchHandle, stubSummary, updatedAt, id);
242	
243	  db.insertTurn = (p: InsertTurnParams) => void insertTurnStmt.run(p);
244	
245	  db.getTurn = (id: string) =>
246	    (getTurnStmt.get(id) as TurnRow | undefined) ?? null;
247	
248	  db.insertBlockReference = (p: InsertBlockReferenceParams): number => {
249	    const info = insertBlockReferenceStmt.run(p);
250	    return Number(info.lastInsertRowid);
251	  };
252	
253	  db.getBlockReferencesForTurn = (turnId: string) =>
254	    getBlockReferencesForTurnStmt.all(turnId) as BlockReferenceRow[];
255	
256	  return db;
257	}
