9	function canonicalize(value: unknown): string {
10	  if (value === undefined || value === null) return "null";
11	  if (typeof value !== "object") return JSON.stringify(value);
12	  if (Array.isArray(value)) {
13	    return "[" + value.map(canonicalize).join(",") + "]";
14	  }
15	  const obj = value as Record<string, unknown>;
16	  const keys = Object.keys(obj)
17	    .filter((k) => obj[k] !== undefined)
18	    .sort();
19	  return (
20	    "{" +
21	    keys
22	      .map((k) => JSON.stringify(k) + ":" + canonicalize(obj[k]))
23	      .join(",") +
24	    "}"
25	  );
26	}
27	
28	function sha256Hex(input: string): string {
29	  return createHash("sha256").update(input, "utf8").digest("hex");
30	}
31	
32	export function placeBreakpoints(
33	  request: AnthropicMessagesRequest,
34	  boundaries: RegionBoundaries,
35	  prevState: PrefixState | undefined,
36	): Breakpoints {
37	  const prefix_hash = sha256Hex(
38	    canonicalize({ system: request.system, tools: request.tools }),
39	  );
40	
41	  let middle_hash: string | null = null;
42	  if (
43	    boundaries.middle_end_in_messages !== null &&
44	    boundaries.middle_end_in_messages > 0
45	  ) {
46	    middle_hash = sha256Hex(
47	      canonicalize(
48	        request.messages.slice(0, boundaries.middle_end_in_messages),
49	      ),
50	    );

50	    );
51	  }
52	
53	  const include_middle_breakpoint =
54	    middle_hash !== null &&
55	    prevState !== undefined &&
56	    prevState.middle_hash === middle_hash;
57	
58	  return { prefix_hash, middle_hash, include_middle_breakpoint };
59	}
