1	import type { MutatedRequest, OrchestratorInput } from "./types.js";
2	import { CacheStateTracker } from "./cache-state-tracker.js";
3	import { reorder } from "./reorderer.js";
4	import { placeBreakpoints } from "./breakpoint-placer.js";
5	import { mutateRequest } from "./request-mutator.js";
6	
7	export type {
8	  AnthropicCacheControl,
9	  AnthropicMessage,
10	  AnthropicMessageContent,
11	  AnthropicMessagesRequest,
12	  AnthropicSystemBlock,
13	  AnthropicTool,
14	  Breakpoints,
15	  Classification,
16	  MutatedRequest,
17	  OrchestratorInput,
18	  RegionBoundaries,
19	} from "./types.js";
20	
21	export { CacheStateTracker } from "./cache-state-tracker.js";
22	
23	const FIVE_MINUTES_MS = 5 * 60 * 1000;
24	
25	export function orchestrate(
26	  input: OrchestratorInput,
27	  tracker: CacheStateTracker,
28	): MutatedRequest {
29	  try {
30	    const boundaries = reorder(input.message_classifications);
31	    const prevState = tracker.get(input.workspace_id);
32	    const breakpoints = placeBreakpoints(
33	      input.original_request,
34	      boundaries,
35	      prevState,
36	    );
37	    const mutated = mutateRequest(
38	      input.original_request,
39	      boundaries,
40	      breakpoints,
41	    );
42	
43	    const now = Date.now();
44	    tracker.update(input.workspace_id, {
45	      workspace_id: input.workspace_id,
46	      prefix_hash: breakpoints.prefix_hash,
47	      middle_hash: breakpoints.middle_hash,
48	      prefix_token_count: 0,
49	      ttl_class: "5m",
50	      cached_at_ms: now,
51	      last_read_at_ms: now,
52	      expected_expiry_ms: now + FIVE_MINUTES_MS,
53	    });
54	
55	    return {
56	      request: mutated,
57	      mutated: true,
58	      prefix_hash: breakpoints.prefix_hash,
59	      middle_hash: breakpoints.middle_hash,
60	      signals: ["ok"],
61	    };
62	  } catch (err) {
63	    // orchestrate must never throw; log and fail-open with the unmutated
64	    // request. M7 will swap console.error for the structured logger so ops
65	    // can alert on `error:fallback` signal rate. Mirrors the classifier
66	    // pattern landed in M2 (commit 546b32a).
67	    console.error("[cachelane] orchestrate error", err);
68	    return {
69	      request: input.original_request,
70	      mutated: false,
71	      prefix_hash: "",
72	      middle_hash: null,
73	      signals: ["error:fallback"],
74	    };
75	  }
76	}
