1	import type { Classification, RegionBoundaries } from "./types.js";
2	
3	// Messages keep their chronological order — Anthropic API requires it.
4	// The "middle" region is the contiguous run of SEMI/STABLE classified
5	// messages at the head of messages[]. The first VOLATILE message ends the
6	// middle; everything from that index onward is the suffix.
7	//
8	// We read `c.volatility` and ignore the rest of the Classification for now.
9	// M5's K-pruner will additionally consult `c.isPinned` and `c.kind` for the
10	// stub-materialisation decision; M3 keeps the contract narrow.
11	export function reorder(
12	  message_classifications: Classification[],
13	): RegionBoundaries {
14	  let middle_end: number | null = null;
15	  for (let i = 0; i < message_classifications.length; i++) {
16	    const v = message_classifications[i].volatility;
17	    if (v === "SEMI" || v === "STABLE") {
18	      middle_end = i + 1;
19	    } else {
20	      break;
21	    }
22	  }
23	  return { middle_end_in_messages: middle_end };
24	}
